import React, { useState } from 'react';

const RatingModal = ({ store, currentRating, onClose, onSubmit }) => {
  const [rating, setRating] = useState(currentRating || 0);
  const [hoverRating, setHoverRating] = useState(0);

  const handleSubmit = () => {
    if (rating >= 1 && rating <= 5) {
      onSubmit(rating);
    } else {
      alert('Please select a rating between 1 and 5');
    }
  };

  return (
    <div style={{
      position: 'fixed',
      top: 0,
      left: 0,
      right: 0,
      bottom: 0,
      backgroundColor: 'rgba(0,0,0,0.5)',
      display: 'flex',
      justifyContent: 'center',
      alignItems: 'center',
      zIndex: 1000
    }}>
      <div className="card" style={{ maxWidth: '400px', width: '90%' }}>
        <h3 style={{ marginBottom: '15px' }}>Rate {store.name}</h3>
        
        <div style={{ textAlign: 'center', marginBottom: '20px' }}>
          <div className="rating">
            {[1, 2, 3, 4, 5].map((star) => (
              <span
                key={star}
                className={`star ${star <= (hoverRating || rating) ? 'active' : ''}`}
                onClick={() => setRating(star)}
                onMouseEnter={() => setHoverRating(star)}
                onMouseLeave={() => setHoverRating(0)}
                style={{ fontSize: '40px', cursor: 'pointer' }}
              >
                ★
              </span>
            ))}
          </div>
          <p style={{ marginTop: '10px', color: '#666' }}>
            {rating > 0 ? `Selected: ${rating} star${rating > 1 ? 's' : ''}` : 'Select a rating'}
          </p>
        </div>
        
        <div style={{ display: 'flex', gap: '10px', justifyContent: 'flex-end' }}>
          <button className="btn" onClick={onClose} style={{ background: '#ddd' }}>
            Cancel
          </button>
          <button className="btn btn-primary" onClick={handleSubmit}>
            Submit Rating
          </button>
        </div>
      </div>
    </div>
  );
};

export default RatingModal;
